def abs_a_plus_abs_b(a, b):
    if a < 0:
        a = -a
    if b < 0:
        b = -b
    return a + b

def a_minus_abs_b(a, b):
    if b < 0:
        return a + b
    else:
        return a - b

exercises.canonical_solution:
def logging_in(num_guesses):
    if num_guesses == 0:
        return 'Bitte einloggen'
    elif num_guesses <= 2:
        return 'Falsches Passwort'
    elif num_guesses <= 4:
        return f'Noch {5 - num_guesses} Versuche'
    else:
        return 'Konto gesperrt'

