exercises.canonical_solution:
def simple_calc(a, b, operator):
    if operator == '+':
        return a + b
    elif operator == '-':
        return a - b
    elif operator == '*':
        return a * b
    elif operator == '/':
        if b == 0:
            return None
        return a / b
    else:
        return None

concept_variations.canonical_solution:
def safe_divide(a, b):
    if b == 0:
        return 0
    return a / b

def apply_op(a, b, op):
    if op == 'add':
        return a + b
    elif op == 'sub':
        return a - b
    elif op == 'mul':
        return a * b
    elif op == 'div':
        return a / b if b != 0 else None
    else:
        return None

def calc_with_power(a, b, op):
    if op == '+':
        return a + b
    elif op == '-':
        return a - b
    elif op == '*':
        return a * b
    elif op == '/':
        return a / b if b != 0 else None
    elif op == '**':
        return a ** b
    else:
        return None

exercises.canonical_solution:
def triangle_q(a, b, c):
    if a == b == c:
        return 'equilateral'
    elif a == b or b == c or a == c:
        return 'isosceles'
    else:
        return 'scalene'

